import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"影流之镰","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/影流之镰.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/影流之镰.md"}'),o={name:"4.资源分区/1.血统与训练/6.一次性血统/影流之镰.md"};function b(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"影流之镰",tabindex:"-1"},[n("影流之镰 "),r("a",{class:"header-anchor",href:"#影流之镰","aria-label":'Permalink to "影流之镰"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序009")])])],-1),s('<h1 id="影流之镰-1" tabindex="-1">影流之镰 <a class="header-anchor" href="#影流之镰-1" aria-label="Permalink to &quot;影流之镰&quot;">​</a></h1><p>影流之镰<br> C+2400<br> 一次性血统<br> 前提：使用巨镰<br> 在购买完毕这个血统以后，你获得【巨镰横扫】、【利刃纵贯】、【掠影步】三个技能。<br> 你在购买该血统以后，获得一个特殊的计数值：英雄等级。每经过一场影片，你的英雄等级就提高一级。</p><p>影流刺客凯隐在与暗裔杀手拉亚斯特争夺控制权。一人胜，则另一人死。<br> 在影片内杀死远程同级单位时会给影流刺客充能一点，而杀死近战同级单位会给暗裔杀手充能一点，影片结束后，对比二者数值大小，将较高者计入影片充能。<br> 在你英雄等级达到六级后，根据积累的影片充能数决定变身为哪一方；或者也可以再等待两场影片，此时双方都可以选择，影流之镰可以在主神空间中选择变身为哪一个形态，之后永久保持这个形态。</p><p>若暗裔杀手胜利，则会完全侵蚀掉影流之镰这个脆弱的凡人，并现身为一个可怕的暗裔杀手，额外获得如下效果：<br> -你造成的所有伤害会根据英雄等级数为你治疗你的严重伤害（有韧性伤害时优先治疗韧性伤害）【医疗点=每点快速医疗*12】，这个数值初始为0，每有2级英雄等级，就会获得1点以此法生效的快速医疗。<br> -在变身后，每获得20点额外的生命，就会再获得1点使用巨镰横扫时的武器伤害。<br> -【利刃纵贯】现在使用时不会再降低被攻击者的速度，而是改为敌人进行一次反射豁免对抗出目，若对抗失败，则其会向上被击飞豁免失败数米，并失去所有闪避防御。当你英雄等级达到8级，被击飞的单位不能进行自主移动。这是D级环境来源的击飞效果，这个效果会随着暗裔杀手的人物支线等级提升变为C/B/A/S级。<br> -【裂舍影】造成的伤害还会再额外治愈你等同于你以暗裔杀手能力获得的快速医疗的严重伤害（有韧性伤害时优先治疗韧性伤害），医疗点独立计算，计算方式与第一条相同。</p><p>若影流刺客胜利，则会摧毁暗裔杀手拉亚斯特并成为大师级影流刺客，额外获得如下效果：<br> -每个战斗场景开始时，你的首次攻击还会再获得额外的法术强度，这个数值初始为0，每经过两场影片获得1点法术强度。<br> -在使用【利刃纵贯】时，你额外再获得15米的使用距离，且该技能可以结合在移动中使用。<br> -获得15米额外的移动速度，当你被减速效果作用时，你会无视30米对你移动速度的减值。<br> -在你脱离【裂舍影】状态时，可以额外再向外移动等同于你一个移动动作移动距离的距离。</p><p>巨镰横扫<br> 使用巨镰横扫是一个标准动作，冲刺，并挥舞巨镰，使用巨镰横扫会先向前以一个自由动作移动15米，在那之后对自身触及范围内的所有敌人进行一次攻击检定，正常攻击防御。</p><p>利刃纵贯<br> 使用利刃纵贯是一个标准动作，向上挥出镰刀，对一个触及范围内的敌人进行一次攻击，那个敌人需进行一次反射豁免对抗出目，受到等同于二者差值的速度减少，这个效果将持续一轮</p><p>掠影步<br> 使用掠影步是一个移动动作，这视为一种步法。使用掠影步进行一次移动，那次移动将额外获得D5C10B15A20S25点移动速度，并且可以如同拥有遁地一般穿越地形，视为拥有3点遁力。在你以此法在本回合内首次进入地形时，你会再额外恢复D1C2B3A4S5点严重伤害（有韧性伤害时优先治疗韧性伤害），【医疗点12/24/36/48/60】，你使用过掠影步的回合结束时，若你仍然在地形之中，则你会被强制挤出该地形，并受到相当于位移距离的冲击伤害。</p><p>裂舍影<br> B+2000<br> 在解锁这个技能后，你的攻击将会标记敌人一轮，以一个整轮动作使用，对触及范围内的一个你标记的敌人进行一次攻击，正常攻击对方防御。若这次攻击命中，你会钻入被攻击者的体内，他的头顶将会出现一柄镰刀，你在此期间受到的所有伤害都会由该角色承受，这视为他对你有全遮蔽，但目标本身可以正常攻击到你，这是一个B级创伤来源的胁迫效果。 当你的下个回合开始时，你将立即从他的体内离开，而镰刀刺落下来进而造成等同于上一轮攻击检定在计算所有能力与防御后的实际伤害。你也可以在这段时间内随时选择离开其体内，以此法正常造成伤害，若被裂舍影作用的目标在此期间死亡，则你无法避免的立即从其体内离开。裂舍影的CD为10轮或一个场景取低。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(o,[["render",b]]);export{f as __pageData,m as default};
